const files = await client.beta.files.list();

console.log(files.data);
// Returns paginated list with pagination_token

const file = await client.beta.files.retrieve({
    file_id: "file_abc123xyz"
});

console.log({
    id: file.id,
    filename: file.filename,
    size_bytes: file.size_bytes,
    content_type: file.content_type,
    created_at: file.created_at
});

const fileData = await client.beta.files.download({
    file_id: "file_abc123xyz"
});

// Save to file
import * as fs from "fs";
fs.writeFileSync("downloaded_report.pdf", fileData);

# Best for single-use tasks
uploaded = client.beta.files.upload(
    file=("temp.pdf", open("temp.pdf", "rb"), "application/pdf")
)

# Use once
response = client.messages.create(
    messages=[{
        "content": [
            {"type": "document", "source": {"type": "file", "file_id": uploaded.id}}
        ]
    }]
)

# Delete immediately
client.beta.files.delete(uploaded.id)

# Best for long-term document analysis
uploaded = client.beta.files.upload(
    file=("contract.pdf", open("contract.pdf", "rb"), "application/pdf")
)
file_id = uploaded.id

# Use across many conversations
for day in range(10):
    response = client.messages.create(
        messages=[{
            "content": [
                {"type": "document", "source": {"type": "file", "file_id": file_id}},
                {"type": "text", "text": f"Question for day {day}"}
            ]
        }]
    )

# Delete after project ends
client.beta.files.delete(file_id)

import anthropic

client = anthropic.Anthropic()

try:
    client.beta.files.delete("file_abc123xyz")
    print("File deleted successfully")
except anthropic.NotFoundError:
    print("File not found (already deleted?)")
except anthropic.PermissionError:
    print("Permission denied - file not in workspace")
